import sys

def solve(data: str) -> str:
    tokens = iter(map(int, data.split()))
    n, m, color_count = next(tokens), next(tokens), next(tokens)
    edges = [(next(tokens), next(tokens)) for _ in range(m)]
    neighbors = [set() for _ in range(n)]
    for left, right in edges:
        neighbors[left].add(right); neighbors[right].add(left)
    assigned = [-1] * n
    def search() -> bool:
        unassigned = [node for node in range(n) if assigned[node] < 0]
        if not unassigned:
            return True
        node = min(unassigned, key=lambda item: sum(assigned[neighbor] < 0 for neighbor in neighbors[item]))
        used = {assigned[neighbor] for neighbor in neighbors[node]}
        for color in range(color_count):
            if color in used:
                continue
            assigned[node] = color
            if search():
                return True
        assigned[node] = -1
        return False
    return ' '.join(map(str, assigned)) if search() else 'none'

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
